import { ChevronDown, ChevronUp, Languages, Loader2, RotateCcw, ZoomIn } from "lucide-react";
import { Dialog, DialogContent } from "@/components/ui/dialog";

interface ChefDishShowcaseCardProps {
  badgeLabel: string;
  badgeIndex: number;
  title: string;
  summary?: string | null;
  imageUrl?: string | null;
  imageAlt: string;
  expanded: boolean;
  onToggleExpanded: () => void;
  detailLabel: string;
  detailText?: string | null;
  insightLabel: string;
  insightText?: string | null;
  translateLabel?: string;
  onTranslateInsight?: () => void;
  isTranslatingInsight?: boolean;
  /** Translate dish content (name + description) */
  dishTranslateLabel?: string;
  onTranslateDish?: () => void;
  isTranslatingDish?: boolean;
  showDishTranslated?: boolean;
  previewImage: { src: string; alt: string } | null;
  setPreviewImage: (image: { src: string; alt: string } | null) => void;
  footer?: React.ReactNode;
  clickToPreview?: string;
}

export const ChefDishShowcaseCard = ({
  badgeLabel,
  badgeIndex,
  title,
  summary,
  imageUrl,
  imageAlt,
  expanded,
  onToggleExpanded,
  detailLabel,
  detailText,
  insightLabel,
  insightText,
  translateLabel,
  onTranslateInsight,
  isTranslatingInsight = false,
  dishTranslateLabel,
  onTranslateDish,
  isTranslatingDish = false,
  showDishTranslated = false,
  previewImage,
  setPreviewImage,
  footer,
  clickToPreview = "Click to preview",
}: ChefDishShowcaseCardProps) => {
  return (
    <>
      <article className="group relative overflow-hidden rounded-[22px] border border-border/60 bg-card/95 shadow-[0_16px_40px_-28px_hsl(var(--foreground)/0.2)] transition-all duration-300 hover:border-primary/30 hover:shadow-[0_22px_48px_-30px_hsl(var(--foreground)/0.24)]">
        <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top_left,hsl(var(--primary)/0.06),transparent_38%)]" />

        <div className="relative p-3 md:p-4">
          <button type="button" onClick={onToggleExpanded} className="w-full text-left">
            <div className="flex items-start gap-3 md:gap-4">
              {!expanded && (
                <div className="shrink-0">
                  {imageUrl ? (
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        setPreviewImage({ src: imageUrl, alt: imageAlt });
                      }}
                      className="group/image relative block h-[88px] w-[88px] overflow-hidden rounded-[18px] border border-border/50 bg-muted/30 md:h-[108px] md:w-[108px]"
                      title={clickToPreview}
                    >
                      <img
                        src={imageUrl}
                        alt={imageAlt}
                        className="h-full w-full object-cover transition-transform duration-500 group-hover/image:scale-[1.04]"
                        loading="lazy"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-foreground/20 via-transparent to-transparent" />
                      <div className="absolute right-2 top-2 inline-flex items-center gap-1 rounded-full bg-background/92 px-2 py-0.5 text-[10px] font-medium text-foreground shadow-sm opacity-0 transition-opacity group-hover/image:opacity-100">
                        <ZoomIn className="h-3 w-3" />
                        预览
                      </div>
                    </button>
                  ) : (
                    <div className="flex h-[88px] w-[88px] items-center justify-center rounded-[18px] border border-border/50 bg-muted/30 px-2 text-center text-[11px] text-muted-foreground md:h-[108px] md:w-[108px]">
                      暂无图片
                    </div>
                  )}
                </div>
              )}

              <div className="min-w-0 flex-1 pt-0.5">
                <div className="flex items-start justify-between gap-3">
                  <div className="min-w-0 flex-1">
                    <div className="mb-1.5 flex items-center gap-2">
                      <span className="inline-flex h-7 w-7 items-center justify-center rounded-full border border-primary/20 bg-primary/10 text-xs font-semibold text-primary">
                        {badgeIndex}
                      </span>
                      <span className="text-[11px] font-medium text-primary/80">{badgeLabel}</span>
                    </div>
                    <h3 className="text-base font-bold leading-tight text-foreground md:text-[20px]">
                      {title}
                    </h3>
                    {!expanded && summary ? (
                      <p className="mt-1.5 max-w-3xl line-clamp-2 text-xs leading-5 text-muted-foreground md:text-[13px] md:leading-6">
                        {summary}
                      </p>
                    ) : null}
                  </div>
                  <div className="flex items-center gap-1.5 mt-0.5 shrink-0">
                    {onTranslateDish && dishTranslateLabel && !expanded && (
                      <button
                        type="button"
                        onClick={(e) => {
                          e.stopPropagation();
                          onTranslateDish();
                        }}
                        disabled={isTranslatingDish}
                        className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium transition-colors disabled:opacity-50 ${
                          showDishTranslated
                            ? "text-primary bg-primary/10"
                            : "text-muted-foreground hover:text-primary hover:bg-primary/10"
                        }`}
                      >
                        {isTranslatingDish ? (
                          <Loader2 className="h-3 w-3 animate-spin" />
                        ) : showDishTranslated ? (
                          <RotateCcw className="h-3 w-3" />
                        ) : (
                          <Languages className="h-3 w-3" />
                        )}
                        {dishTranslateLabel}
                      </button>
                    )}
                    <span className="rounded-full border border-border/60 bg-background/90 p-1.5 text-muted-foreground shadow-sm">
                      {expanded ? <ChevronUp className="h-3.5 w-3.5" /> : <ChevronDown className="h-3.5 w-3.5" />}
                    </span>
                  </div>
                </div>

                {!expanded && footer ? <div className="mt-3">{footer}</div> : null}
              </div>
            </div>
          </button>

          {expanded ? (
            <div className="mt-4 border-t border-border/50 pt-4">
              <div className="flex gap-4">
                {/* Left: Image */}
                {imageUrl ? (
                  <div className="shrink-0">
                    <button
                      type="button"
                      onClick={(e) => {
                        e.stopPropagation();
                        setPreviewImage({ src: imageUrl, alt: imageAlt });
                      }}
                      className="group/image relative block h-[180px] w-[180px] overflow-hidden rounded-[18px] border border-border/50 bg-muted/30 md:h-[240px] md:w-[240px]"
                      title={clickToPreview}
                    >
                      <img
                        src={imageUrl}
                        alt={imageAlt}
                        className="h-full w-full object-cover transition-transform duration-500 group-hover/image:scale-[1.04]"
                        loading="lazy"
                      />
                      <div className="absolute inset-0 bg-gradient-to-t from-foreground/20 via-transparent to-transparent" />
                      <div className="absolute right-2 top-2 inline-flex items-center gap-1 rounded-full bg-background/92 px-2 py-0.5 text-[10px] font-medium text-foreground shadow-sm opacity-0 transition-opacity group-hover/image:opacity-100">
                        <ZoomIn className="h-3 w-3" />
                        预览
                      </div>
                    </button>
                  </div>
                ) : null}

                {/* Right: Description + Neijing stacked */}
                <div className="min-w-0 flex-1 space-y-3">
                  {detailText ? (
                    <section className="rounded-[18px] bg-muted/30 p-3.5 ring-1 ring-border/35">
                      <div className="mb-2 flex items-center justify-between gap-3">
                        <p className="text-xs font-semibold text-foreground">{detailLabel}</p>
                        {onTranslateDish && dishTranslateLabel ? (
                          <button
                            type="button"
                            onClick={(e) => {
                              e.stopPropagation();
                              onTranslateDish();
                            }}
                            disabled={isTranslatingDish}
                            className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium transition-colors disabled:opacity-50 ${
                              showDishTranslated
                                ? "text-primary bg-primary/10"
                                : "text-muted-foreground hover:text-primary hover:bg-primary/10"
                            }`}
                          >
                            {isTranslatingDish ? (
                              <Loader2 className="h-3 w-3 animate-spin" />
                            ) : showDishTranslated ? (
                              <RotateCcw className="h-3 w-3" />
                            ) : (
                              <Languages className="h-3 w-3" />
                            )}
                            {dishTranslateLabel}
                          </button>
                        ) : null}
                      </div>
                      <p className="text-xs leading-6 text-foreground/90 whitespace-pre-wrap md:text-[13px] md:leading-7">{detailText}</p>
                    </section>
                  ) : null}

                  {insightText ? (
                    <section className="rounded-[18px] border border-primary/15 bg-background/90 p-3.5 shadow-[inset_0_1px_0_hsl(var(--background))]">
                      <div className="mb-2 flex items-center justify-between gap-3">
                        <p className="text-xs font-bold text-foreground md:text-[13px]">{insightLabel}</p>
                        {onTranslateInsight && translateLabel ? (
                          <button
                            type="button"
                            onClick={(e) => {
                              e.stopPropagation();
                              onTranslateInsight();
                            }}
                            disabled={isTranslatingInsight}
                            className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium text-primary transition-colors hover:bg-primary/10 disabled:opacity-50"
                          >
                            {isTranslatingInsight ? <Loader2 className="h-3 w-3 animate-spin" /> : <Languages className="h-3 w-3" />}
                            {translateLabel}
                          </button>
                        ) : null}
                      </div>
                      <p className="text-xs leading-6 text-foreground whitespace-pre-wrap md:text-[13px] md:leading-7">{insightText}</p>
                    </section>
                  ) : null}
                </div>
              </div>

              {footer ? <div className="mt-3">{footer}</div> : null}
            </div>
          ) : null}
        </div>
      </article>

      <Dialog open={!!previewImage} onOpenChange={(open) => !open && setPreviewImage(null)}>
        <DialogContent className="max-w-4xl border-border/60 bg-background p-2 sm:p-3">
          {previewImage ? (
            <img
              src={previewImage.src}
              alt={previewImage.alt}
              className="max-h-[80vh] w-full rounded-[20px] object-contain"
            />
          ) : null}
        </DialogContent>
      </Dialog>
    </>
  );
};
