import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Landmark, X, Loader2, MapPin } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";

interface NearbyLandmarksProps {
  lat: number;
  lng: number;
  restaurantId: string;
}

interface LandmarkItem {
  id: string;
  name: string;
  name_en: string | null;
  name_pt: string | null;
  image_url: string | null;
  lat: number;
  lng: number;
  distance?: number;
}

function haversineDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLng = ((lng2 - lng1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos((lat1 * Math.PI) / 180) * Math.cos((lat2 * Math.PI) / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export const NearbyLandmarks = ({ lat, lng, restaurantId }: NearbyLandmarksProps) => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { getLocalizedField } = useLocalizedContent();
  const [landmarks, setLandmarks] = useState<LandmarkItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [open, setOpen] = useState(false);

  const fetchLandmarks = async () => {
    if (loaded) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from("restaurants")
        .select("id, name, name_en, name_pt, image_url, lat, lng")
        .eq("template", "landmark")
        .eq("visible", true)
        .neq("id", restaurantId);

      if (!error && data) {
        const withDistance = data
          .filter((l) => l.lat && l.lng)
          .map((l) => ({
            ...l,
            distance: haversineDistance(lat, lng, l.lat!, l.lng!),
          }))
          .filter((l) => l.distance <= 3)
          .sort((a, b) => a.distance - b.distance);
        setLandmarks(withDistance);
      }
    } catch {}
    setLoading(false);
    setLoaded(true);
  };

  const handleOpen = (isOpen: boolean) => {
    setOpen(isOpen);
    if (isOpen && !loaded) {
      fetchLandmarks();
    }
  };

  return (
    <Popover open={open} onOpenChange={handleOpen}>
      <PopoverTrigger asChild>
        <button
          className="inline-flex items-center justify-center h-9 w-9 md:h-10 md:w-10 rounded-md bg-secondary text-secondary-foreground hover:bg-secondary/80 shadow-lg transition-colors"
          title={t("landmarks.nearbyTitle")}
        >
          <Landmark className="w-4 h-4 md:w-5 md:h-5" />
        </button>
      </PopoverTrigger>
      <PopoverContent align="end" className="w-72 p-0 max-h-[70vh] flex flex-col">
        <div className="p-3 border-b border-border shrink-0">
          <p className="text-sm font-semibold text-foreground flex items-center gap-1.5">
            <Landmark className="w-4 h-4 text-primary" />
            {t("landmarks.nearbyTitle")}
            {!loading && landmarks.length > 0 && (
              <span className="text-xs font-normal text-muted-foreground ml-auto">
                {landmarks.length}
              </span>
            )}
          </p>
        </div>
        <div className="p-2 overflow-y-auto overscroll-contain flex-1">
          {loading ? (
            <div className="flex items-center justify-center py-6">
              <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
            </div>
          ) : landmarks.length === 0 ? (
            <p className="text-xs text-muted-foreground text-center py-4">
              {t("landmarks.noNearby")}
            </p>
          ) : (
            <div className="space-y-1">
              {landmarks.map((landmark) => (
                <button
                  key={landmark.id}
                  className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-muted/60 active:bg-muted transition-colors text-left"
                  onClick={() => {
                    setOpen(false);
                    navigate(`/restaurant/${landmark.id}`);
                  }}
                >
                  <div className="shrink-0 w-10 h-10 rounded-lg overflow-hidden bg-muted">
                    {landmark.image_url ? (
                      <img
                        src={landmark.image_url}
                        alt={getLocalizedField(landmark, "name")}
                        className="w-full h-full object-cover"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <Landmark className="w-4 h-4 text-muted-foreground" />
                      </div>
                    )}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-foreground truncate">
                      {getLocalizedField(landmark, "name")}
                    </p>
                    <p className="text-xs text-muted-foreground flex items-center gap-1">
                      <MapPin className="w-3 h-3" />
                      {landmark.distance?.toFixed(1)} km
                    </p>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
};
